def gen(rng, size):
    n = max(2, size)
    chars = []
    bars = 0
    for _ in range(n):
        r = rng.random()
        if r < 0.2:
            chars.append('|')
            bars += 1
        elif r < 0.5:
            chars.append('*')
        else:
            chars.append(rng.choice('abcdefghijklmnopqrstuvwxyz'))
    if bars % 2 == 1:
        chars.append('|')
    return [''.join(chars)]

